//! DEBUG: dump FLUX VAE decoder raw float RGB on a fixed deterministic
//! (already-unscaled) latent for numeric cross-check against a diffusers
//! AutoencoderKL Decoder. Emits a flat little-endian f32 binary [3, H, W]
//! channel-major plus a JSON manifest.

use std::io::Write;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_flux_mmdit::{debug_vae_decode_raw, debug_vae_decode_stages};

fn stats(v: &[f32]) -> (f32, f32, f32, f32) {
    let n = v.len() as f32;
    let mean = v.iter().sum::<f32>() / n;
    let var = v.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n;
    let mn = v.iter().cloned().fold(f32::INFINITY, f32::min);
    let mx = v.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    (mean, var.sqrt(), mn, mx)
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        eprintln!("usage: flux-vae-dump <knot> <out-prefix> [lh] [lw]");
        std::process::exit(2);
    }
    let knot_path = &args[1];
    let out_prefix = &args[2];
    let lh: usize = args.get(3).and_then(|s| s.parse().ok()).unwrap_or(8);
    let lw: usize = args.get(4).and_then(|s| s.parse().ok()).unwrap_or(8);

    let knot = KnotWeights::load_metadata_only(knot_path).expect("load knot metadata");

    // Stage-by-stage stats for divergence localization.
    let stages = debug_vae_decode_stages(knot_path, &knot, lh, lw).expect("vae stages");
    for (name, v) in &stages {
        let (mean, std, mn, mx) = stats(v);
        eprintln!(
            "STAGE {:>10} len={:>7} mean={:+.5} std={:.5} min={:+.4} max={:+.4}",
            name,
            v.len(),
            mean,
            std,
            mn,
            mx
        );
        let mut sf = std::fs::File::create(format!("{out_prefix}_stage_{name}.bin")).unwrap();
        for x in v.iter() {
            sf.write_all(&x.to_le_bytes()).unwrap();
        }
    }

    let (rgb, h, w) = debug_vae_decode_raw(knot_path, &knot, lh, lw).expect("vae decode raw");

    let (mean, std, mn, mx) = stats(&rgb);
    eprintln!(
        "vae rgb [3,{h},{w}] len={} mean={:+.5} std={:.5} min={:+.4} max={:+.4}",
        rgb.len(),
        mean,
        std,
        mn,
        mx
    );

    let bin_path = format!("{out_prefix}.bin");
    let json_path = format!("{out_prefix}.json");
    let mut f = std::fs::File::create(&bin_path).expect("create bin");
    for x in &rgb {
        f.write_all(&x.to_le_bytes()).unwrap();
    }
    let manifest = format!(
        "{{\n  \"h\": {h}, \"w\": {w}, \"channels\": 3,\n  \"fields\": {{\n    \"rgb\": {{\"offset\": 0, \"len\": {}}}\n  }}\n}}\n",
        rgb.len()
    );
    std::fs::write(&json_path, manifest).expect("write json");
    eprintln!("wrote {bin_path} ({} f32) + {json_path}", rgb.len());
}
